import type { ModuleApi } from "../../types/module/api/ModuleApi";
import { MODULE_ID, MODULE_TITLE } from "../constants";

export function createModuleApi(): ModuleApi {
  return {
    id: MODULE_ID,
    logStatus() {
      console.log(`${MODULE_TITLE} is loaded.`);
    },
    title: MODULE_TITLE,
  };
}
